mapper.select:
SELECT * FROM ( SELECT a.*, ROWNUM rnum FROM ( SELECT e.EMP_NO , e.EMP_NM , e.DEPT_CD , d.DEPT_NM , p.POS_NM , CASE WHEN e.EMP_STAT_CD = 'WORK' THEN '재직' WHEN e.EMP_STAT_CD = 'LEAVE' THEN '휴직' WHEN e.EMP_STAT_CD = 'RESIGN' THEN '퇴사' ELSE '기타' END AS empStatNm , e.EMP_STAT_CD AS stts , TO_CHAR(e.HIRE_DT, 'YYYY-MM-DD') AS hireDt FROM EMP e LEFT JOIN DEPT d ON e.DEPT_CD = d.DEPT_CD LEFT JOIN POSITION_MST p ON e.POS_CD = p.POS_CD
(p.USE_YN = 'Y' OR p.USE_YN IS NULL)
AND (e.EMP_NM LIKE '%' || #{params.searchTerm} || '%' OR d.DEPT_NM LIKE '%' || #{params.searchTerm} || '%' OR e.EMP_NO LIKE '%' || #{params.searchTerm} || '%')
AND p.POS_NM LIKE '%' || #{params.posNm} || '%'
AND d.DEPT_NM LIKE '%' || #{params.deptNm} || '%'
AND (CASE WHEN e.EMP_STAT_CD = 'WORK' THEN '재직' WHEN e.EMP_STAT_CD = 'LEAVE' THEN '휴직' WHEN e.EMP_STAT_CD = 'RESIGN' THEN '퇴사' ELSE '기타' END) = #{params.empStatNm}
) a /* pageSize를 recordSize로 수정하여 프론트에서 보낸 개수만큼 가져오도록 변경 */ WHERE ROWNUM <= #{paging.page} * #{paging.recordSize} ) WHERE rnum > (#{paging.page} - 1) * #{paging.recordSize}
